    }
    if (empty($targets)) return;
    SWUQueueMayChooseTarget(intval($player), array_values($targets), "Exhaust_a_Force_unit?", "Choose_a_Force_unit", "EXHAUST_UNIT");
};
$onAttackAbilities["LOF_033:0"] = function($player, $mzID) {
