    if ($obj === null || !empty($obj->removed)) return;
    $controller = intval($obj->Controller ?? $player);
    OnExhaustCard(intval($player), $lastDecision);
    SWUCreateUnitToken($controller, 'JTL_T02'); // X-Wing (Space, 2/2)
};

