            if ($scid === 'SOR_T02') { if (is_array($sub)) $sub['removed'] = true; else $sub->removed = true; }
        }
        unset($sub);
    }
    DecisionQueueController::CleanupRemovedCards();
    SWUDealDamageToUnit($lastDecision, 3, intval($player));
};

