    global $playerID;
    $playerID = intval($player);
    if (strpos($lastDecision, 'Base') !== false) {
        $tp = (strpos($lastDecision, 'theirBase') !== false) ? GetOpponent(intval($player)) : intval($player);
        SWUDealDamageToBase(1, $tp);
