    $targets = [];
    foreach ($hand as $mz) {
        $h = GetZoneObject($mz);
        if ($h !== null && empty($h->removed) && strpos((string)(CardAspect($h->CardID ?? '') ?? ''), 'Heroism') !== false) $targets[] = $mz;
    }
