// a unit." Two independent conditional effects, both windows. (Friendly-upgrade flag set by _SWUOnUpgradeDefeated.)
$whenPlayedAbilities["ASH_039:0"] =
$onAttackEndAbilities["ASH_039:0"] = function($player, $mzID) {
